def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    memo_primes = {}
    def is_prime(num):
        if num in memo_primes:
            return memo_primes[num]
        if num < 2:
            memo_primes[num] = False
            return False
        if num == 2 or num == 3:
            memo_primes[num] = True
            return True
        if num % 2 == 0 or num % 3 == 0:
            memo_primes[num] = False
            return False
        i = 5
        while i * i <= num:
            if num % i == 0 or num % (i + 2) == 0:
                memo_primes[num] = False
                return False
            i += 6
        memo_primes[num] = True
        return True
    def harmonic_sum(n):
        s = 0.0
        for i in range(1, n+1):
            s += 1 / i
        return s
    def fermi_dirac(x, mu, kT):
        return 1 / (np.exp((x - mu) / kT) + 1)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            if item > cap:
                priorities[idx] = -np.inf
            else:
                priorities[idx] = 900 + cap
            continue
        ratio = item / cap
        score = 0.0
        if ratio < 0.1:
            for p in range(1, 10):
                coef = np.cos(p * cap * 0.7) + np.sin(p * item * 1.3)
                score += coef * np.exp(-p * ratio * 3) * p
            prime_divs = 0
            for d in range(2, int(cap // 3) + 1):
                if cap % d == 0 and is_prime(d):
                    prime_divs += d ** 0.3
            score += prime_divs * 2.5
            if cap % 2 == 0:
                score *= 1.15
        elif 0.1 <= ratio < 0.3:
            for a in range(1, 7):
                val = np.sin(a * np.pi * ratio) * (a ** 0.5)
                score += val * np.log1p(cap)
            h_sum = harmonic_sum(int(cap))
            score += h_sum / (ratio + 0.5)
            if cap % 7 == 0 or cap % 11 == 0:
                score *= 1.12
        elif 0.3 <= ratio <= 0.6:
            fd = fermi_dirac(ratio * 10, 5, 0.8)
            score += fd * 80
            for x in range(1, int(cap // 4) + 1):
                if cap % x == 0 and x % 5 == 2:
                    score += np.sqrt(x) * 3
            trig_sum = sum(np.tan(ratio * np.pi * i / 6) for i in range(1,5))
            score += trig_sum / (int(ratio * 10) + 2)
        elif 0.6 < ratio < 1:
            base = 40 / (1 + np.exp(-15 * (ratio - 0.75)))
            score += base
            for y in range(1, 15):
                if is_prime(y) and (y % 4 == 3):
                    score += y * 0.7
            if cap % 8 == 0:
                score *= 0.88
            if ratio > 0.85:
                score += (1 - ratio) * 55
        elif 1 <= ratio < 1.3:
            penalty = 0
            step = max(1, int(cap//7))
            for i in range(1, step+1):
                if cap % i == 0:
                    penalty += (i**1.3) * np.cos(i * ratio)
            fract_part = ratio - int(ratio)
            for j in range(1, 10):
                val = ((fract_part * j * 1000) % 11) / 11 * 8
                penalty += val * np.sin(j * np.pi / 4)
            score += penalty / (step + 3)
            score -= (ratio - 1) * 65
            if cap % 13 == 0:
                score += 20
            if cap % 17 == 0:
                score *= 0.85
        elif 1.3 <= ratio < 2.5:
            base = (2.5 - ratio) * 40
            score += base
            for q in range(1, int(min(20, cap))):
                if cap % q == 0:
                    if q % 3 == 0:
                        score += np.log(q + 1) * 4
                    else:
                        score -= np.sqrt(q)
            fract_part = ratio - int(ratio)
            for r in range(1, 15):
                score += np.cos(fract_part * r * np.pi * 0.7) * 3
            if ratio > 2:
                score += 15 * np.tanh(cap / 20)
        else:
            comp_sum = 0
            lim = int(min(30, cap))
            for w in range(1, lim):
                if cap % w == 0:
                    if w % 5 == 0:
                        comp_sum += np.exp(-w/10) * 10
                    else:
                        comp_sum += (w**0.2) * 2
            fract_part = ratio - int(ratio)
            for z in range(1,20):
                comp_sum += np.sin(fract_part * z * np.pi / 2) * 4
            score += comp_sum
            score += (ratio - 3) * 50
            if ratio > 5:
                for m in range(1, int(cap//4)+1):
                    if m % 6 == 1:
                        score += np.cos(m) * 5
            if int(cap) % 9 == 0:
                score *= 1.05
        if int(cap) % 3 == 0 and ratio < 2.0:
            score *= 1.09
        if int(cap) % 7 == 0 and ratio > 0.7:
            score *= 0.78
        if ratio > 4 and int(cap) % 6 == 0:
            score += 25
        if int(cap) % 15 == 0:
            score *= 0.9
        priorities[idx] = score
    finite_mask = np.isfinite(priorities)
    if np.any(finite_mask):
        min_p = np.min(priorities[finite_mask])
    else:
        min_p = 0
    priorities = np.where(finite_mask, priorities, min_p + 350)
    return priorities
